const { S3 } = require('aws-sdk');
const { exec } = require('child_process');
const util = require('util');
const execPromise = util.promisify(exec);

const s3 = new S3();

exports.handler = async (event) => {
    try {
        const record = event.Records[0];
        const bucket = record.s3.bucket.name;
        const key = record.s3.object.key;
        const outputFormat = record.s3.object.metadata.outputformat;
        
        // Validate output format
        const allowedFormats = ['jpg', 'png', 'webp', 'gif'];
        if (!allowedFormats.includes(outputFormat)) {
            throw new Error('Invalid output format');
        }
        
        // Sanitize key
        const sanitizedKey = key.replace(/[^a-zA-Z0-9._\-\/]/g, '');
        if (sanitizedKey !== key) {
            throw new Error('Invalid key format');
        }
        
        // Download image from S3
        const s3Response = await s3.getObject({
            Bucket: bucket,
            Key: sanitizedKey
        }).promise();
        
        // Create temporary file paths
        const inputPath = `/tmp/${Date.now()}-${sanitizedKey.split('/').pop()}`;
        const outputPath = inputPath.replace(/\.[^/.]+$/, `.${outputFormat}`);
        
        // Write input file
        const fs = require('fs');
        fs.writeFileSync(inputPath, s3Response.Body);
        
        // Convert image using ImageMagick
        const command = `convert "${inputPath}" -quality 90 "${outputPath}"`;
        await execPromise(command);
        
        // Upload converted image back to S3
        const outputBuffer = fs.readFileSync(outputPath);
        const uploadParams = {
            Bucket: bucket,
            Key: `converted/${sanitizedKey.split('/').slice(0, -1).join('/')}/${Date.now()}-${sanitizedKey.split('/').pop().split('.')[0]}.${outputFormat}`,
            Body: outputBuffer,
            ContentType: `image/${outputFormat}`
        };
        
        await s3.upload(uploadParams).promise();
        
        // Clean up temporary files
        fs.unlinkSync(inputPath);
        fs.unlinkSync(outputPath);
        
        return {
            statusCode: 200,
            body: JSON.stringify({
                message: 'Image converted successfully',
                inputKey: sanitizedKey,
                outputKey: uploadParams.Key
            })
        };
    } catch (error) {
        console.error('Error processing image:', error);
        throw error;
    }
};